/**
 * `done` 的统一入参结构。
 * Unified `done` input payload.
 *
 * @typedef {object} DonePayload
 * @property {number|string} [status] 响应状态码或状态行 / Response status code or status line.
 * @property {string} [url] 响应 URL / Response URL.
 * @property {Record<string, any>} [headers] 响应头 / Response headers.
 * @property {string|ArrayBuffer|ArrayBufferView} [body] 响应体 / Response body.
 * @property {ArrayBuffer} [bodyBytes] 二进制响应体 / Binary response body.
 * @property {string} [policy] 指定策略名 / Preferred policy name.
 */

/**
 * 结束脚本执行并按平台转换参数。
 * Complete script execution with platform-specific parameter mapping.
 *
 * 说明:
 * Notes:
 * - 这是调用入口，平台原生 `$done` 差异在内部处理
 * - This is the call entry and native `$done` differences are handled internally
 * - Worker 不调用 `$done` 或退出进程，仅记录日志
 * - Worker neither calls `$done` nor exits the process; it only logs
 * - Node.js 不调用 `$done`，而是直接退出进程
 * - Node.js does not call `$done`; it exits the process directly
 * - 未识别平台仅记录结束日志，不会强制退出
 * - Unknown runtimes only log completion and do not force an exit
 *
 * @param {DonePayload} [object={}] 统一响应对象 / Unified response object.
 * @returns {void}
 */
function done(object = {}) {
	switch ($app) {
		case "Surge":
			if (object.policy) Lodash.set(object, "headers.X-Surge-Policy", object.policy);
			Console.log("🚩 执行结束!", `🕛 ${new Date().getTime() / 1000 - $script.startTime} 秒`);
			$done(object);
			break;
		case "Loon":
			if (object.policy) object.node = object.policy;
			Console.log("🚩 执行结束!", `🕛 ${(new Date() - $script.startTime) / 1000} 秒`);
			$done(object);
			break;
		case "Stash":
			if (object.policy) Lodash.set(object, "headers.X-Stash-Selected-Proxy", encodeURI(object.policy));
			Console.log("🚩 执行结束!", `🕛 ${(new Date() - $script.startTime) / 1000} 秒`);
			$done(object);
			break;
		case "Egern":
			Console.log("🚩 执行结束!");
			$done(object);
			break;
		case "Shadowrocket":
			Console.log("🚩 执行结束!");
			$done(object);
			break;
		case "Quantumult X":
			if (object.policy) Lodash.set(object, "opts.policy", object.policy);
			object = Lodash.pick(object, ["status", "url", "headers", "body", "bodyBytes"]);
			switch (typeof object.status) {
				case "number":
					object.status = `HTTP/1.1 ${object.status} ${StatusTexts[object.status]}`;
					break;
				case "string":
				case "undefined":
					break;
				default:
					throw new TypeError(`${Function.name}: 参数类型错误, status 必须为数字或字符串`);
			}
			if (object.body instanceof ArrayBuffer) {
				object.bodyBytes = object.body;
				object.body = undefined;
			} else if (ArrayBuffer.isView(object.body)) {
				object.bodyBytes = object.body.buffer.slice(object.body.byteOffset, object.body.byteLength + object.body.byteOffset);
				object.body = undefined;
			} else if (object.body) object.bodyBytes = undefined;
			Console.log("🚩 执行结束!");
			$done(object);
			break;
		case "Worker":
			Console.log("🚩 执行结束!");
			break;
		case "Node.js":
			Console.log("🚩 执行结束!");
			process.exit(1);
			break;
		default:
			Console.log("🚩 执行结束!");
			break;
	}
}

/**
 * 跨平台持久化存储适配器。
 * Cross-platform persistent storage adapter.
 *
 * 设计目标:
 * Design goal:
 * - 仿照 Web Storage (`Storage`) 接口设计
 * - Modeled after Web Storage (`Storage`) interface
 * - 统一 VPN App 脚本环境中的持久化读写接口
 * - Unify persistence APIs across VPN app script environments
 *
 * 支持后端:
 * Supported backends:
 * - Surge/Loon/Stash/Egern/Shadowrocket: `$persistentStore`
 * - Quantumult X: `$prefs`
 * - Worker: 内存缓存（非持久化）
 * - Worker: in-memory cache (non-persistent)
 * - Node.js: 本地 `box.dat`
 * - Node.js: local `box.dat`
 *
 * 支持路径键:
 * Supports path key:
 * - `@root.path.to.value`
 *
 * 与 Web Storage 的已知差异:
 * Known differences from Web Storage:
 * - 支持 `@key.path` 深路径读写（Web Storage 原生不支持）
 * - Supports `@key.path` deep-path access (not native in Web Storage)
 * - `removeItem/clear` 并非所有平台都可用
 * - `removeItem/clear` are not available on every platform
 * - 读取时会尝试 `JSON.parse`，写入对象会 `JSON.stringify`
 * - Reads try `JSON.parse`, writes stringify objects
 *
 * @link https://developer.mozilla.org/en-US/docs/Web/API/Storage
 * @link https://developer.mozilla.org/zh-CN/docs/Web/API/Storage
 */
class Storage {
	/**
	 * Worker / Node.js 环境下的内存数据缓存。
	 * In-memory data cache for Worker / Node.js runtime.
	 *
	 * @type {Record<string, any>|null}
	 */
	static data = null;

	/**
	 * Node.js 持久化文件名。
	 * Data file name used in Node.js.
	 *
	 * @type {string}
	 */
	static dataFile = "box.dat";

	/**
	 * `@key.path` 解析正则。
	 * Regex for `@key.path` parsing.
	 *
	 * @type {RegExp}
	 */
	static #nameRegex = /^@(?<key>[^.]+)(?:\.(?<path>.*))?$/;

	/**
	 * 读取存储值。
	 * Read value from persistent storage.
	 *
	 * @param {string} keyName 键名或路径键 / Key or path key.
	 * @param {*} [defaultValue=null] 默认值 / Default value when key is missing.
	 * @returns {*}
	 */
	static getItem(keyName, defaultValue = null) {
		let keyValue = defaultValue;
		// 如果以 @
		switch (keyName.startsWith("@")) {
			case true: {
				const { key, path } = keyName.match(Storage.#nameRegex)?.groups;
				keyName = key;
				let value = Storage.getItem(keyName, {});
				if (typeof value !== "object") value = {};
				keyValue = Lodash.get(value, path);
				try {
					keyValue = JSON.parse(keyValue);
				} catch {}
				break;
			}
			default:
				switch ($app) {
					case "Surge":
					case "Loon":
					case "Stash":
					case "Egern":
					case "Shadowrocket":
						keyValue = $persistentStore.read(keyName);
						break;
					case "Quantumult X":
						keyValue = $prefs.valueForKey(keyName);
						break;
					case "Worker":
						Storage.data = Storage.data ?? {};
						keyValue = Storage.data[keyName];
						break;
					case "Node.js":
						Storage.data = Storage.#loaddata(Storage.dataFile);
						keyValue = Storage.data?.[keyName];
						break;
					default:
						keyValue = Storage.data?.[keyName] || null;
						break;
				}
				try {
					keyValue = JSON.parse(keyValue);
				} catch {
					// do nothing
				}
				break;
		}
		return keyValue ?? defaultValue;
	}

	/**
	 * 写入存储值。
	 * Write value into persistent storage.
	 *
	 * @param {string} keyName 键名或路径键 / Key or path key.
	 * @param {*} keyValue 写入值 / Value to store.
	 * @returns {boolean}
	 */
	static setItem(keyName = new String(), keyValue = new String()) {
		let result = false;
		switch (typeof keyValue) {
			case "object":
				keyValue = JSON.stringify(keyValue);
				break;
			default:
				keyValue = String(keyValue);
				break;
		}
		switch (keyName.startsWith("@")) {
			case true: {
				const { key, path } = keyName.match(Storage.#nameRegex)?.groups;
				keyName = key;
				let value = Storage.getItem(keyName, {});
				if (typeof value !== "object") value = {};
				Lodash.set(value, path, keyValue);
				result = Storage.setItem(keyName, value);
				break;
			}
			default:
				switch ($app) {
					case "Surge":
					case "Loon":
					case "Stash":
					case "Egern":
					case "Shadowrocket":
						result = $persistentStore.write(keyValue, keyName);
						break;
					case "Quantumult X":
						result = $prefs.setValueForKey(keyValue, keyName);
						break;
					case "Worker":
						Storage.data = Storage.data ?? {};
						Storage.data[keyName] = keyValue;
						result = true;
						break;
					case "Node.js":
						Storage.data = Storage.#loaddata(Storage.dataFile);
						Storage.data[keyName] = keyValue;
						Storage.#writedata(Storage.dataFile);
						result = true;
						break;
					default:
						result = Storage.data?.[keyName] || null;
						break;
				}
				break;
		}
		return result;
	}

	/**
	 * 删除存储值。
	 * Remove value from persistent storage.
	 *
	 * 平台说明:
	 * Platform notes:
	 * - Quantumult X: `$prefs.removeValueForKey`
	 * - Surge: 通过 `$persistentStore.write(null, keyName)` 删除
	 * - 其余平台当前返回 `false`
	 *
	 * @param {string} keyName 键名或路径键 / Key or path key.
	 * @returns {boolean}
	 */
	static removeItem(keyName) {
		let result = false;
		switch (keyName.startsWith("@")) {
			case true: {
				const { key, path } = keyName.match(Storage.#nameRegex)?.groups;
				keyName = key;
				let value = Storage.getItem(keyName);
				if (typeof value !== "object") value = {};
				Lodash.unset(value, path);
				result = Storage.setItem(keyName, value);
				break;
			}
			default:
				switch ($app) {
					case "Surge":
						result = $persistentStore.write(null, keyName);
						break;
					case "Loon":
					case "Stash":
					case "Egern":
					case "Shadowrocket":
						result = false;
						break;
					case "Quantumult X":
						result = $prefs.removeValueForKey(keyName);
						break;
					case "Worker":
						Storage.data = Storage.data ?? {};
						delete Storage.data[keyName];
						result = true;
						break;
					case "Node.js":
						// result = false;
						Storage.data = Storage.#loaddata(Storage.dataFile);
						delete Storage.data[keyName];
						Storage.#writedata(Storage.dataFile);
						result = true;
						break;
					default:
						result = false;
						break;
				}
				break;
		}
		return result;
	}

	/**
	 * 清空存储。
	 * Clear storage.
	 *
	 * @returns {boolean}
	 */
	static clear() {
		let result = false;
		switch ($app) {
			case "Surge":
			case "Loon":
			case "Stash":
			case "Egern":
			case "Shadowrocket":
				result = false;
				break;
			case "Quantumult X":
				result = $prefs.removeAllValues();
				break;
			case "Worker":
				Storage.data = {};
				result = true;
				break;
			case "Node.js":
				// result = false;
				Storage.data = Storage.#loaddata(Storage.dataFile);
				Storage.data = {};
				Storage.#writedata(Storage.dataFile);
				result = true;
				break;
			default:
				result = false;
				break;
		}
		return result;
	}

	/**
	 * 从 Node.js 数据文件加载 JSON。
	 * Load JSON data from Node.js data file.
	 *
	 * @private
	 * @param {string} dataFile 数据文件名 / Data file name.
	 * @returns {Record<string, any>}
	 */
	static #loaddata = dataFile => {
		if ($app === "Node.js") {
			this.fs = this.fs ? this.fs : require("fs");
			this.path = this.path ? this.path : require("path");
			const curDirDataFilePath = this.path.resolve(dataFile);
			const rootDirDataFilePath = this.path.resolve(process.cwd(), dataFile);
			const isCurDirDataFile = this.fs.existsSync(curDirDataFilePath);
			const isRootDirDataFile = !isCurDirDataFile && this.fs.existsSync(rootDirDataFilePath);
			if (isCurDirDataFile || isRootDirDataFile) {
				const datPath = isCurDirDataFile ? curDirDataFilePath : rootDirDataFilePath;
				try {
					return JSON.parse(this.fs.readFileSync(datPath));
				} catch (e) {
					return {};
				}
			} else return {};
		} else return {};
	};

	/**
	 * 将内存数据写入 Node.js 数据文件。
	 * Persist in-memory data to Node.js data file.
	 *
	 * @private
	 * @param {string} [dataFile=this.dataFile] 数据文件名 / Data file name.
	 * @returns {void}
	 */
	static #writedata = (dataFile = this.dataFile) => {
		if ($app === "Node.js") {
			this.fs = this.fs ? this.fs : require("fs");
			this.path = this.path ? this.path : require("path");
			const curDirDataFilePath = this.path.resolve(dataFile);
			const rootDirDataFilePath = this.path.resolve(process.cwd(), dataFile);
			const isCurDirDataFile = this.fs.existsSync(curDirDataFilePath);
			const isRootDirDataFile = !isCurDirDataFile && this.fs.existsSync(rootDirDataFilePath);
			const jsondata = JSON.stringify(this.data);
			if (isCurDirDataFile) {
				this.fs.writeFileSync(curDirDataFilePath, jsondata);
			} else if (isRootDirDataFile) {
				this.fs.writeFileSync(rootDirDataFilePath, jsondata);
			} else {
				this.fs.writeFileSync(curDirDataFilePath, jsondata);
			}
		}
	};
}

/**
 * 已标准化的 `$argument` 快照。
 * Normalized `$argument` snapshot.
 */
const $argument = globalThis.$argument ?? {};

const MATCH_URL_RE = /^https:\/\/api\.shortcutstudio\.app\/(?:generate|users\/me\/limits|sign)(?:[/?#]|$)/i;
const GENERATE_URL_RE = /^https:\/\/api\.shortcutstudio\.app\/generate(?:[/?#]|$)/i;
const SIGN_URL_RE = /^https:\/\/api\.shortcutstudio\.app\/sign(?:[/?#]|$)/i;
const DEVICE_ID_HEADER = "X-Device-Installation-ID";
const CONTENT_LENGTH_HEADER = "Content-Length";
const STORAGE_KEY = "Yu9191.ShortcutStudio.Generate.DeviceInstallationID";
const DEFAULT_DEVICE_ID_REUSE_LIMIT = 2;
const DEFAULT_ARGUMENT = {
	thinkingMode: "auto",
	searchWebMode: "off",
	deviceIdReuseLimit: DEFAULT_DEVICE_ID_REUSE_LIMIT,
	signRewrite: "off",
};
const memoryStorage = {};

async function Request(request) {
	if (!request?.url || !MATCH_URL_RE.test(String(request.url))) {
		return { $request: request };
	}

	const args = { ...DEFAULT_ARGUMENT, ...parseArgument(globalThis.$argument ?? $argument) };
	const url = String(request.url);
	if (SIGN_URL_RE.test(url) && normalizeMode(args.signRewrite) !== "on") {
		return { $request: request };
	}

	request.headers = normalizeHeaders(request.headers);

	const bodyResult = GENERATE_URL_RE.test(url) ? rewriteBody(request.body, args) : { body: request.body, changed: false };
	request.body = bodyResult.body;

	const deviceInstallationId = pickArgument(args, ["deviceId", "deviceInstallationId", "installationId"]) || nextDeviceInstallationId(args);
	if (deviceInstallationId) setHeader(request.headers, DEVICE_ID_HEADER, deviceInstallationId);
	if (bodyResult.changed) removeHeader(request.headers, CONTENT_LENGTH_HEADER);

	Console.debug("ShortcutStudio request rewritten");
	return { $request: request };
}

function rewriteBody(body, argument = {}) {
	if (typeof body !== "string" || body.trim() === "") {
		return { body, changed: false };
	}

	let payload;
	try {
		payload = JSON.parse(body);
	} catch {
		return { body, changed: false };
	}

	if (!payload || typeof payload !== "object" || Array.isArray(payload)) {
		return { body, changed: false };
	}

	let changed = false;
	const thinkingMode = normalizeMode(pickArgument(argument, ["thinkingMode", "thinkingModeSelection", "thinking", "reasoning", "enableReasoning"]));
	if (thinkingMode) {
		payload.thinkingModeSelection = thinkingMode;
		if (thinkingMode === "auto") {
			payload.thinkingMode = "auto";
			payload.enableReasoning = true;
			payload.reasoningEffort = "high";
		} else {
			payload.thinkingMode = thinkingMode === "on";
			payload.enableReasoning = thinkingMode === "on";
			payload.reasoningEffort = thinkingMode === "on" ? "high" : "minimal";
		}
		changed = true;
	}

	const searchWebMode = normalizeMode(pickArgument(argument, ["searchWebMode", "searchWebModeSelection", "searchWeb", "web"]));
	if (searchWebMode) {
		payload.searchWebMode = searchWebMode;
		changed = true;
	}

	const model = pickArgument(argument, ["model", "modelId"]);
	if (model) {
		payload.model = String(model);
		changed = true;
	}

	return {
		body: changed ? JSON.stringify(payload) : body,
		changed,
	};
}

function nextDeviceInstallationId(argument = {}) {
	const reuseLimit = normalizePositiveInteger(pickArgument(argument, ["deviceIdReuseLimit", "idReuseLimit", "reuseLimit", "reuse"]), DEFAULT_DEVICE_ID_REUSE_LIMIT);
	const storageKey = String(pickArgument(argument, ["deviceIdStorageKey", "storageKey"]) || STORAGE_KEY);
	const state = readState(storageKey);
	if (!state.id || !Number.isFinite(state.uses) || state.uses >= reuseLimit) {
		state.id = createDeviceInstallationId();
		state.uses = 0;
	}
	state.uses += 1;
	if (!writeState(storageKey, state)) {
		return createDeviceInstallationId();
	}
	return state.id;
}

function createDeviceInstallationId() {
	const bytes = randomBytes(16);
	bytes[6] = (bytes[6] & 0x0f) | 0x40;
	bytes[8] = (bytes[8] & 0x3f) | 0x80;
	const hex = Array.from(bytes, byte => byte.toString(16).padStart(2, "0"));
	const id = `${hex.slice(0, 4).join("")}-${hex.slice(4, 6).join("")}-${hex.slice(6, 8).join("")}-${hex.slice(8, 10).join("")}-${hex.slice(10, 16).join("")}`;
	return id;
}

function normalizeHeaders(headers) {
	if (!headers || typeof headers !== "object") return {};
	return { ...headers };
}

function setHeader(headers, name, value) {
	const existingKey = findHeaderKey(headers, name);
	headers[existingKey || name] = String(value);
}

function removeHeader(headers, name) {
	const key = findHeaderKey(headers, name);
	if (key) delete headers[key];
}

function normalizeMode(value) {
	const normalized = String(value ?? "").trim().toLowerCase();
	if (normalized === "auto") return "auto";
	if (normalized === "on" || normalized === "1" || normalized === "true" || normalized === "yes" || normalized === "enable" || normalized === "enabled") return "on";
	if (normalized === "off" || normalized === "0" || normalized === "false" || normalized === "no" || normalized === "disable" || normalized === "disabled") return "off";
	return "";
}

function parseArgument(argument) {
	if (!argument) return {};
	if (typeof argument === "object") return { ...argument };
	const result = {};
	String(argument)
		.replace(/^\?/, "")
		.split("&")
		.filter(Boolean)
		.forEach(pair => {
			const [rawKey = "", rawValue = ""] = pair.split("=", 2);
			const key = decodeQueryPart(rawKey);
			if (key) result[key] = decodeQueryPart(rawValue);
		});
	return result;
}

function randomBytes(size) {
	const bytes = new Uint8Array(size);
	const cryptoObject = globalThis.crypto || globalThis.msCrypto;
	if (cryptoObject && typeof cryptoObject.getRandomValues === "function") {
		cryptoObject.getRandomValues(bytes);
		return bytes;
	}
	for (let i = 0; i < bytes.length; i += 1) bytes[i] = Math.floor(Math.random() * 256);
	return bytes;
}

function readState(key) {
	const raw = readStorage(key);
	if (!raw) return { id: "", uses: 0 };
	try {
		const state = typeof raw === "string" ? JSON.parse(raw) : raw;
		return {
			id: typeof state.id === "string" ? state.id : "",
			uses: Number(state.uses) || 0,
		};
	} catch {
		return { id: "", uses: 0 };
	}
}

function writeState(key, state) {
	return writeStorage(key, state);
}

function readStorage(key) {
	try {
		return Storage.getItem(key, "");
	} catch {}
	try {
		if (globalThis.localStorage && typeof globalThis.localStorage.getItem === "function") return globalThis.localStorage.getItem(key) || "";
	} catch {}
	return memoryStorage[key] || "";
}

function writeStorage(key, value) {
	try {
		if (Storage.setItem(key, value) !== false) return true;
	} catch {}
	try {
		if (globalThis.localStorage && typeof globalThis.localStorage.setItem === "function") {
			globalThis.localStorage.setItem(key, JSON.stringify(value));
			return true;
		}
	} catch {}
	memoryStorage[key] = JSON.stringify(value);
	return true;
}

function findHeaderKey(headers, name) {
	const expected = String(name).toLowerCase();
	return Object.keys(headers).find(key => key.toLowerCase() === expected) || "";
}

function normalizePositiveInteger(value, fallback) {
	const parsed = Number.parseInt(String(value ?? ""), 10);
	if (Number.isFinite(parsed) && parsed > 0) return parsed;
	return fallback;
}

function pickArgument(argument, names) {
	for (const name of names) {
		if (argument[name] !== undefined && argument[name] !== null && String(argument[name]).trim() !== "") return argument[name];
	}
	return "";
}

function decodeQueryPart(value) {
	try {
		return decodeURIComponent(String(value).replace(/\+/g, " "));
	} catch {
		return String(value);
	}
}

